import { setScriptKey, getLicenseStatus, validatePackage, PackageMetadata, LicenseMessage } from '@progress/kendo-licensing';

let _parsedPackageMetadata: PackageMetadata = null;

try {
    _parsedPackageMetadata = Object.freeze(JSON.parse('$PACKAGE_METADATA'));
} catch {
    _parsedPackageMetadata = Object.freeze({
        name: '@progress/kendo-ui',
        productName: 'Kendo UI for jQuery',
        productCode: 'KENDOUICOMPLETE',
        productCodes: ["KENDOUICOMPLETE", "KENDOUI", "UIASPCORE", "KENDOMVC", "KENDOUIMVC"],
        redistributedBy: ['KENDOUI', 'UIASPCORE', 'KENDOMVC', 'KENDOUIMVC'],
        publishDate: 0,
        version: '0.0.0',
        licensingDocsUrl: 'https://www.telerik.com/kendo-jquery-ui/documentation/intro/installation/licensing/activation-errors-and-warnings'
    });
}

const TRUSTED_HOSTS = [/telerik\.com/, /progress\.com/, /stackblitz\.io/, /csb\.app/, /telerik\.io/];
const BANNER_FONT_FAMILY = 'system-ui, -apple-system, "Segoe UI", Roboto, Helvetica, Arial, "Noto Sans", "Liberation Sans", sans-serif';

function applyStyles(el: HTMLElement, styles: { [key: string]: string }): void {
    Object.keys(styles).forEach(k => el.style.setProperty(k, styles[k]));
}

function sanitizeSvg(svg: string): string {
    return svg
        .replace(/\bfillRule\b/g, 'fill-rule')
        .replace(/\bclipRule\b/g, 'clip-rule')
        .replace(/\bstrokeWidth\b/g, 'stroke-width')
        .replace(/\bstrokeDasharray\b/g, 'stroke-dasharray')
        .replace(/\bstrokeLinecap\b/g, 'stroke-linecap')
        .replace(/\bstrokeLinejoin\b/g, 'stroke-linejoin');
}

function addWatermarkOverlay(el: HTMLElement): void {
    const watermark = document.createElement("div");

    applyStyles(watermark, {
        "position": "absolute",
        "width": "100%",
        "height": "100%",
        "pointer-events": "none",
        "top": "0",
        "left": "0",
        "right": "0",
        "bottom": "0"
    });

    const watermarkRoot = watermark.attachShadow({ mode: "closed" });
    const watermarkElement = document.createElement("div");

    applyStyles(watermarkElement, {
        "position": "absolute",
        "top": "0",
        "left": "0",
        "right": "0",
        "bottom": "0",
        "pointer-events": "none",
        "z-index": "101",
        "opacity": "0.12",
        "width": "100%",
        "height": "100%",
        "background-image": "url('data:image/png;base64,')"
    });

    watermarkRoot.appendChild(watermarkElement);
    el.appendChild(watermark);

    const mo = new MutationObserver(function (e) {
        const record = e[0];

        if (record.removedNodes && Array.from(record.removedNodes).indexOf(watermark) > -1) {
            setTimeout(() => {
                el.appendChild(watermark);
            }, 100);
        }

        if (record.type === "attributes" && record.target === watermark) {
            setTimeout(() => {
                watermark.removeAttribute(record.attributeName);
            }, 100);
        }
    });

    mo.observe(el, { childList: true, attributes: true, subtree: true });
}

function createBannerElement(licenseMessage: LicenseMessage): HTMLElement {
    const banner = document.createElement('div');
    banner.setAttribute('id', 'k-license-banner');
    const iconSvg = sanitizeSvg(licenseMessage.notificationIcon.content || '');

    let bodyHTML = licenseMessage.notificationBody || '';
    const titleText = licenseMessage.notificationTitle || '';
    if (titleText && bodyHTML.startsWith(titleText)) {
        bodyHTML = bodyHTML.slice(titleText.length).trim();
    }

    const ctaHTML = licenseMessage.callToAction
        ? `<a id="k-license-cta" href="${licenseMessage.callToAction.link}" target="_blank" rel="noopener noreferrer">${licenseMessage.callToAction.message}</a>`
        : '';

    banner.innerHTML = `
        <span id="k-license-icon">${iconSvg}</span>
        <div id="k-license-content">
            <div id="k-license-title">${titleText}</div>
            <div id="k-license-body">${bodyHTML}</div>
        </div>
        <div id="k-license-actions">
            ${ctaHTML}
            <button id="k-license-close" title="Close">
                <svg width="20" height="20" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M11.9309 3.1838C12.1754 2.93933 12.5712 2.93937 12.8157 3.1838C13.0601 3.4283 13.0601 3.82407 12.8157 4.06857L8.885 7.99923L12.8166 11.9309C13.0611 12.1754 13.0611 12.5721 12.8166 12.8166C12.5721 13.0611 12.1754 13.0611 11.9309 12.8166L7.99925 8.88497L4.06859 12.8166C3.8241 13.0611 3.42732 13.0611 3.18285 12.8166C2.93862 12.5721 2.93851 12.1753 3.18285 11.9309L7.11449 7.99923L3.18382 4.06857C2.93947 3.82413 2.93955 3.42829 3.18382 3.1838C3.42831 2.9393 3.82508 2.9393 4.06957 3.1838L7.99925 7.11349L11.9309 3.1838Z" fill="#212529"/>
                </svg>
            </button>
        </div>
    `;

    applyStyles(banner, {
        'display': 'flex',
        'position': 'fixed',
        'left': '50%',
        'transform': 'translateX(-50%)',
        'width': '100%',
        'border-left': '6px solid rgba(255, 192, 0, 1)',
        'border-top': '1px solid #00000029',
        'border-right': '1px solid #00000029',
        'border-bottom': '1px solid #00000029',
        'background-color': '#ffffff',
        'box-shadow': '0px 4px 5px 0px #0000000A, 0px 2px 4px 0px #00000008',
        'font-size': '14px',
        'font-weight': '400',
        'line-height': '20px',
        'color': '#1E1E1E',
        'justify-content': 'center',
        'z-index': '2000',
        'box-sizing': 'border-box'
    });

    const iconEl = banner.querySelector<HTMLElement>('#k-license-icon');
    applyStyles(iconEl, {
        'display': 'flex',
        'flex-shrink': '0'
    });

    const contentEl = banner.querySelector<HTMLElement>('#k-license-content');
    applyStyles(contentEl, {
        'display': 'flex',
        'flex-direction': 'column',
        'gap': '4px'
    });

    const titleEl = banner.querySelector<HTMLElement>('#k-license-title');
    applyStyles(titleEl, {
        'font-family': BANNER_FONT_FAMILY,
        'font-weight': '700',
        'font-size': '14px',
        'line-height': '142%',
        'font-style': 'Bold',
        'letter-spacing': '0px',
        'vertical-align': 'middle',
        'text-align': 'left'
    });

    const bodyEl = banner.querySelector<HTMLElement>('#k-license-body');
    applyStyles(bodyEl, {
        'font-family': BANNER_FONT_FAMILY,
        'font-weight': '400',
        'font-size': '14px',
        'line-height': '20px',
        'letter-spacing': '0px',
        'vertical-align': 'middle',
        'text-align': 'left'
    });

    const ctaEl = banner.querySelector<HTMLElement>('#k-license-cta');
    if (ctaEl) {
        applyStyles(ctaEl, {
            'display': 'inline-flex',
            'border': 'none',
            'border-radius': '4px',
            'background-color': '#eb0249',
            'color': '#ffffff',
            'padding': '4px 8px',
            'white-space': 'nowrap',
            'text-decoration': 'none',
            'font-family': BANNER_FONT_FAMILY,
            'cursor': 'pointer',
            'position': 'relative',
            'transition': 'background-color 0.2s ease-in-out',
            'outline': 'none'
        });
        ctaEl.addEventListener('mouseenter', function () {
            ctaEl.style.setProperty('background-color', '#b90138');
        });
        ctaEl.addEventListener('mouseleave', function () {
            ctaEl.style.setProperty('background-color', '#eb0249');
        });
    }

    const actionsEl = banner.querySelector<HTMLElement>('#k-license-actions');
    applyStyles(actionsEl, {
        'display': 'flex',
        'align-items': 'center',
        'gap': '16px'
    });

    const closeEl = banner.querySelector<HTMLElement>('#k-license-close');
    applyStyles(closeEl, {
        'display': 'inline-flex',
        'border': 'none',
        'border-radius': '4px',
        'padding': '4px',
        'background-color': 'transparent',
        'cursor': 'pointer',
        'outline': 'none',
        'transition': 'background-color 0.2s ease-in-out'
    });

    closeEl.addEventListener('mouseenter', function () {
        closeEl.style.setProperty('background-color', '#3d3d3d14');
    });

    closeEl.addEventListener('mouseleave', function () {
        closeEl.style.setProperty('background-color', 'transparent');
    });

    const mqMobile = window.matchMedia('(max-width: 499px)');
    const mqTablet = window.matchMedia('(max-width: 767px)');

    const applyResponsiveStyles = function () {
        const isMobile = mqMobile.matches;
        const isTablet = mqTablet.matches;
        const isDesktop = !isTablet;

        applyStyles(banner, {
            'top': isMobile || isTablet ? '0' : '16px',
            'max-width': isDesktop ? '768px' : 'none',
            'border-radius': isDesktop ? '6px' : '0',
            'flex-direction': isMobile ? 'column' : 'row',
            'align-items': isMobile ? 'flex-start' : 'center',
            'padding': isMobile ? '12px' : '0'
        });

        applyStyles(iconEl, {
            'align-self': isMobile ? 'flex-start' : 'center',
            'padding': isMobile ? '0 0 12px 0' : '9px 12px'
        });

        applyStyles(contentEl, {
            'flex': isMobile ? 'none' : '1',
            'padding': isMobile ? '0 0 12px 0' : '12px'
        });

        applyStyles(actionsEl, {
            'padding': isMobile ? '0' : '9px 12px',
            'margin-left': isMobile ? '0' : 'auto',
            'width': isMobile ? '100%' : 'auto'
        });

        if (isMobile) {
            applyStyles(closeEl, { 'position': 'absolute', 'top': '12px', 'right': '12px' });
        } else {
            applyStyles(closeEl, { 'position': 'relative' });
            closeEl.style.removeProperty('top');
            closeEl.style.removeProperty('right');
        }
    };

    applyResponsiveStyles();
    mqMobile.addEventListener('change', applyResponsiveStyles);
    mqTablet.addEventListener('change', applyResponsiveStyles);

    closeEl.addEventListener('click', function () {
        mqMobile.removeEventListener('change', applyResponsiveStyles);
        mqTablet.removeEventListener('change', applyResponsiveStyles);
        banner.hidden = true;
    });

    return banner;
}

function showBanner(licenseMessage: LicenseMessage): void {
    if (document.querySelector('#k-license-banner')) {
        return;
    }

    document.body.appendChild(createBannerElement(licenseMessage));
}

function shouldHideWatermarkAndBanner(): boolean {
    return TRUSTED_HOSTS.some(r => r.test(window.location.hostname));
}

const packageMetadata = _parsedPackageMetadata;

function addWatermarkOverlayAndBanner(el: HTMLElement): void {
    if (shouldHideWatermarkAndBanner()) {
        return;
    }

    const wrappersMetadata = (window as any)._wrappersMetadata as PackageMetadata;
    const { message } = getLicenseStatus(wrappersMetadata || packageMetadata);
    const isValid = validatePackage(wrappersMetadata || packageMetadata);

    if (!message && isValid) {
        return;
    }

    if (message.severity !== 'INFO') {
        addWatermarkOverlay(el);
    }

    showBanner(message);
}

export { setScriptKey, addWatermarkOverlayAndBanner, packageMetadata };
